module div_8bit(
    input clk, input rst, input sign, input [7:0] dividend, input [7:0] divisor, input opn_valid, input res_ready,
    output reg res_valid, output reg [15:0] result
);
    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg start_cnt;
    reg [7:0] NEG_DIVISOR;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            dividend_reg <= 8'b0;
            divisor_reg <= 8'b0;
            SR <= 16'b0;
            cnt <= 4'b0;
            start_cnt <= 1'b0;
            NEG_DIVISOR <= 8'b0;
            res_valid <= 1'b0;
        end else begin
            if (opn_valid && !res_valid) begin
                dividend_reg <= dividend;
                divisor_reg <= divisor;
                SR <= {{8{dividend[7]}}, dividend} << 1;
                NEG_DIVISOR <= ~{divisor[7], divisor} + 1;
                cnt <= 4'b1;
                start_cnt <= 1'b1;
            end

            if (start_cnt) begin
                if (cnt[3]) begin
                    cnt <= 4'b0;
                    start_cnt <= 1'b0;
                    SR <= {SR[14:0], 1'b0};
                    if (SR[15])
                        SR[15:8] <= SR[15:8] + NEG_DIVISOR;
                        SR[15:8] <= SR[15:8];
                    if (SR[15])
                        SR[7:0] <= SR[7:0];
                        SR[7:0] <= SR[7:0] + {8{divisor[7]}};
                end else begin
                    cnt <= cnt + 1;
                    SR <= {SR[14:0], 1'b0};
                    if (SR[15])
                        SR[15:8] <= SR[15:8] + NEG_DIVISOR;
                        SR[15:8] <= SR[15:8];
                    if (SR[15])
                        SR[7:0] <= SR[7:0];
                        SR[7:0] <= SR[7:0] + {8{divisor[7]}};
                end
            end

            if (rst) begin
                res_valid <= 1'b0;
            end else if (cnt == 4'b1000) begin
                res_valid <= 1'b1;
            end else if (res_valid && res_ready) begin
                res_valid <= 1'b0;
            end
        end
    end

    always @(posedge clk) begin
        if (res_valid && res_ready) begin
            result <= {SR[15:8], SR[7:0]};
        end
    end
endmodule
